{"code": "import json
import re

# Load all data files
packages_file = locals()['var_functions.query_db:18']
versions_file = locals()['var_functions.query_db:20']
info_file = locals()['var_functions.query_db:30']

with open(packages_file, 'r') as f:
    packages = json.load(f)

with open(versions_file, 'r') as f:
    versions = json.load(f)

with open(info_file, 'r') as f:
    project_infos = json.load(f)

# Step 1: Create mapping from package to project
package_to_project = {}
for v in versions:
    key = (v['System'], v['Name'], v['Version'])
    package_to_project[key] = v['ProjectName']

# Step 2: Find MIT release packages that have project mapping
mit_packages = {(p['System'], p['Name'], p['Version']): p for p in packages}

# Find matches
matched_packages = {}
matched_projects = set()

for key, project_name in package_to_project.items():
    if key in mit_packages:
        matched_packages[key] = project_name
        matched_projects.add(project_name)

# Step 3: Parse project_info to get fork counts
project_forks = {}
repo_patterns = [
    r'The project ([a-zA-Z0-9_-]+/[a-zA-Z0-9_-]+) (?:is hosted|on GitHub)',
    r'The project (?:named )?([a-zA-Z0-9_-]+/[a-zA-Z0-9_-]+)',
    r'The GitHub project (?:named )?([a-zA-Z0-9_-]+/[a-zA-Z0-9_-]+)',
    r'GitHub project ([a-zA-Z0-9_-]+/[a-zA-Z0-9_-]+)'
]

fork_patterns = [
    r'and (\d+) forks[,\.]',
    r'forked (\d+) times',
    r'forks count of (\d+)',
    r'(\d+) forks and'
]

for info in project_infos:
    info_text = info['Project_Information']
    repo_name = None
    fork_count = None

    for pattern in repo_patterns:
        match = re.search(pattern, info_text)
        if match:
            repo_name = match.group(1)
            break

    for pattern in fork_patterns:
        match = re.search(pattern, info_text)
        if match:
            try:
                fork_count = int(match.group(1))
                break
            except:
                continue

    if repo_name and fork_count is not None:
        project_forks[repo_name] = fork_count

# Step 4: Find top 5 projects
project_fork_list = []
for project_name in matched_projects:
    if project_name in project_forks:
        project_fork_list.append((project_name, project_forks[project_name]))

# Sort by fork count descending
top_5 = sorted(project_fork_list, key=lambda x: x[1], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps({
    'matched_projects': len(matched_projects),
    'projects_with_forks': len(project_fork_list),
    'top_5_projects': top_5
}))"}

