        mit_projects_with_forks.append({
            'project_name': project_name,
            'fork_count': fork_count,
            'package_count': len(mit_projects[project_name])
        })
        if len(mit_projects_with_forks) >= 5:
            break

print('__RESULT__:')
print(json.dumps({
